280	func (f *CommandFactory) runPluginList(cmd *cobra.Command, args []string) error {
281		out := cmd.OutOrStdout()
282		global, _ := cmd.Flags().GetBool("global")
283	
284		loadState, _ := selectInstallState(global)
285		state, err := loadState()
286		if err != nil {
287			return fmt.Errorf("loading state: %w", err)
288		}
289	
290		if len(state.Installed) == 0 {
291			fmt.Fprintln(out, "No plugins installed.")
292			return nil
293		}
294	
295		w := tabwriter.NewWriter(out, 0, 0, 2, ' ', 0)
296		fmt.Fprintln(w, "NAME\tVERSION\tTYPE\tSTATUS")
297		for _, e := range state.Installed {
298			status := "ok"
299			if !e.VerifyFiles() {
300				status = "BROKEN"
301			}
302			fmt.Fprintf(w, "%s\t%s\t%s\t%s\n", e.Name, e.Version, string(e.Type), status)
303		}
304		return w.Flush()
305	}
