385	// commitPluginChanges stages and commits plugin-related changes in the working tree.
386	// Non-fatal: if git operations fail (not a repo, nothing to commit), it's silently skipped.
387	func commitPluginChanges(name, version string) {
388		// Stage the project-local plugin tree and the skill copies.
389		paths := []string{ddxroot.JoinRelative("plugins", name) + string(filepath.Separator), ".agents/skills/",
390			".claude/skills/",
391		}
392		ctx := context.Background()
393		for _, p := range paths {
394			if _, err := os.Stat(p); err == nil {
395				gitAdd := internalgit.Command(ctx, "", "add", p)
396				_ = gitAdd.Run()
397			}
398		}
399	
400		// Check if there's anything to commit.
401		status := internalgit.Command(ctx, "", "diff", "--cached", "--quiet")
402		if status.Run() == nil {
403			return // nothing staged
404		}
405	
406		msg := fmt.Sprintf("chore: install %s %s", name, version)
407		gitCommit := internalgit.Command(ctx, "", "commit", "-m", msg)
408		_ = gitCommit.Run()
409	}
