411	func prepareSymlinkTarget(target string, force bool) error {
412		if info, err := os.Lstat(target); err == nil {
413			if info.Mode()&os.ModeSymlink != 0 || force {
414				if err := os.RemoveAll(target); err != nil {
415					return fmt.Errorf("removing existing %s: %w", target, err)
416				}
417				return nil
418			}
419			return fmt.Errorf("%s already exists (use --force to replace)", target)
420		} else if !os.IsNotExist(err) {
421			return fmt.Errorf("checking existing %s: %w", target, err)
422		}
423		return nil
424	}
