680	func localOverlayPaths(pluginName string, files []string) []string {
681		seen := map[string]bool{}
682		add := func(path string) {
683			path = filepath.ToSlash(strings.TrimSpace(path))
684			path = strings.TrimPrefix(path, "./")
685			if path == "" || strings.HasPrefix(path, "~") || filepath.IsAbs(path) {
686				return
687			}
688			if !seen[path] {
689				seen[path] = true
690			}
691		}
692	
693		add(filepath.ToSlash(ddxroot.JoinRelative("plugins", pluginName)))
694		for _, file := range files {
695			p := filepath.ToSlash(file)
696			for _, prefix := range []string{".agents/skills/", ".claude/skills/"} {
697				if strings.HasPrefix(p, prefix) {
698					rest := strings.TrimPrefix(p, prefix)
699					name := strings.Split(rest, "/")[0]
700					if name != "" {
701						add(prefix + name)
702					}
703				}
704			}
705		}
706	
707		paths := make([]string, 0, len(seen))
708		for p := range seen {
709			paths = append(paths, p)
710		}
711		sort.Strings(paths)
712		return paths
713	}
