766	func localSkillSourceRoots(pluginRoot string, mappings []registry.InstallMapping) ([]string, error) {
767		var roots []string
768		seen := map[string]bool{}
769		for _, mapping := range mappings {
770			source := strings.TrimSpace(mapping.Source)
771			if source == "" {
772				continue
773			}
774			candidate := filepath.Clean(filepath.Join(pluginRoot, filepath.FromSlash(source)))
775			info, err := os.Stat(candidate)
776			if os.IsNotExist(err) {
777				continue
778			}
779			if err != nil {
780				return nil, err
781			}
782			if !info.IsDir() {
783				return nil, fmt.Errorf("%s: skill source is not a directory", candidate)
784			}
785			if seen[candidate] {
786				continue
787			}
788			seen[candidate] = true
789			roots = append(roots, candidate)
790		}
791		return roots, nil
792	}
