1050			".ddx/workers/",
1051			"node_modules/",
1052			"tmp/",
1053			"website/node_modules/",
1054			"website/public/",
1055			"website/resources/",
1056			"website/test-results/",
1057			"website/playwright-report/",
1058		} {
1059			if strings.HasPrefix(rel, prefix) {
1060				return true
1061			}
1062		}
1063		return false
1064	}
