1218	// newSearchCommand creates the "ddx search <query>" command.
1219	func (f *CommandFactory) newSearchCommand() *cobra.Command {
1220		return &cobra.Command{
1221			Use:   "search <query>",
1222			Short: "Search available packages",
1223			Long:  `Search the DDx registry for packages matching the given query.`,
1224			Args:  cobra.ExactArgs(1),
1225			RunE:  f.runSearch,
1226		}
1227	}
1228	
1229	func (f *CommandFactory) runSearch(cmd *cobra.Command, args []string) error {
1230		query := args[0]
1231		out := cmd.OutOrStdout()
1232	
1233		reg := registry.BuiltinRegistry()
1234		results := reg.Search(query)
1235	
1236		if len(results) == 0 {
1237			fmt.Fprintf(out, "No packages found matching %q\n", query)
1238			return nil
1239		}
1240	
1241		w := tabwriter.NewWriter(out, 0, 0, 2, ' ', 0)
1242		fmt.Fprintln(w, "NAME\tVERSION\tTYPE\tDESCRIPTION")
1243		for _, pkg := range results {
1244			fmt.Fprintf(w, "%s\t%s\t%s\t%s\n",
1245				pkg.Name,
1246				pkg.Version,
1247				string(pkg.Type),
1248				pkg.Description,
1249			)
1250		}
1251		return w.Flush()
1252	}
1253	
1254	func (f *CommandFactory) newOutdatedCommand() *cobra.Command {
1255		cmd := &cobra.Command{
1256			Use:   "outdated",
1257			Short: "List installed packages with available updates",
1258			Long:  `Check installed packages against the registry and list those with newer versions available.`,
1259			Args:  cobra.NoArgs,
1260			RunE:  f.runOutdated,
1261		}
1262		cmd.Flags().Bool("json", false, "Output as JSON")
1263		return cmd
1264	}
1265	
1266	func (f *CommandFactory) runOutdated(cmd *cobra.Command, args []string) error {
1267		out := cmd.OutOrStdout()
1268		asJSON, _ := cmd.Flags().GetBool("json")
1269	
1270		state, err := registry.LoadState()
1271		if err != nil {
1272			return fmt.Errorf("reading installed state: %w", err)
1273		}
1274		if len(state.Installed) == 0 {
1275			fmt.Fprintln(out, "No packages installed.")
1276			return nil
1277		}
1278	
1279		reg := registry.BuiltinRegistry()
1280	
1281		type outdatedEntry struct {
1282			Name             string `json:"name"`
1283			InstalledVersion string `json:"installed_version"`
1284			LatestVersion    string `json:"latest_version"`
1285		}
1286	
1287		var outdated []outdatedEntry
1288		for _, entry := range state.Installed {
1289			pkg, err := reg.Find(entry.Name)
1290			if err != nil {
1291				continue // not in registry, skip
1292			}
1293			if pkg.Version != entry.Version {
1294				outdated = append(outdated, outdatedEntry{
1295					Name:             entry.Name,
1296					InstalledVersion: entry.Version,
1297					LatestVersion:    pkg.Version,
1298				})
1299			}
1300		}
1301	
1302		if len(outdated) == 0 {
1303			fmt.Fprintln(out, "All installed packages are up to date.")
1304			return nil
1305		}
1306	
1307		if asJSON {
1308			enc := json.NewEncoder(out)
1309			enc.SetIndent("", "  ")
1310			return enc.Encode(outdated)
1311		}
1312	
1313		w := tabwriter.NewWriter(out, 0, 0, 2, ' ', 0)
1314		fmt.Fprintln(w, "NAME\tINSTALLED\tLATEST")
1315		for _, o := range outdated {
1316			fmt.Fprintf(w, "%s\t%s\t%s\n", o.Name, o.InstalledVersion, o.LatestVersion)
1317		}
1318		return w.Flush()
1319	}
