110	func SetMasterWorktree(ctx context.Context, projectRoot, masterPath string) error {
111		if ctx == nil {
112			ctx = context.Background()
113		}
114	
115		root := Path(ctx, projectRoot)
116		return withBootstrapLock(root, func() error {
117			registryPath := filepath.Join(root, "worktrees.json")
118			registry, err := readWorktreeRegistry(registryPath)
119			if err != nil {
120				return err
121			}
122	
123			canonicalPath, err := canonicalWorktreePath(masterPath)
124			if err != nil {
125				return err
126			}
127	
128			now := time.Now().UTC().Format(time.RFC3339Nano)
129			hostname, err := os.Hostname()
130			if err != nil || strings.TrimSpace(hostname) == "" {
131				hostname = "unknown"
132			}
133	
134			changed := upsertWorktreeRegistryEntry(&registry, canonicalPath, now, hostname)
135			if registry.Master != canonicalPath {
136				registry.Master = canonicalPath
137				changed = true
138			}
139			if !changed {
140				return nil
141			}
142			return writeWorktreeRegistry(registryPath, registry)
143		})
144	}
