23	func TestPluginLookup_PrefersProjectOverGlobal(t *testing.T) {
24		projectRoot := makeInTreeRoot(t)
25		pluginName := "myplugin"
26	
27		// Create plugin in both project and global layers.
28		projectPlugin := filepath.Join(projectRoot, ddxroot.DirName, "plugins", pluginName)
29		if err := os.MkdirAll(projectPlugin, 0o755); err != nil {
30			t.Fatalf("mkdir project plugin: %v", err)
31		}
32	
33		xdg := t.TempDir()
34		t.Setenv("XDG_DATA_HOME", xdg)
35		globalPlugin := filepath.Join(xdg, "ddx", "global", "plugins", pluginName)
36		if err := os.MkdirAll(globalPlugin, 0o755); err != nil {
37			t.Fatalf("mkdir global plugin: %v", err)
38		}
39	
40		gotPath, gotLayer, err := ResolvePlugin(context.Background(), projectRoot, pluginName)
41		if err != nil {
42			t.Fatalf("ResolvePlugin: unexpected error: %v", err)
43		}
44		if gotLayer != "project" {
45			t.Errorf("layer = %q, want %q", gotLayer, "project")
46		}
47		if gotPath != projectPlugin {
48			t.Errorf("path = %q, want %q", gotPath, projectPlugin)
49		}
