52	func TestPluginLookup_FallsBackToGlobal(t *testing.T) {
53		projectRoot := makeInTreeRoot(t)
54		pluginName := "myplugin"
55	
56		// No project-layer copy.
57		xdg := t.TempDir()
58		t.Setenv("XDG_DATA_HOME", xdg)
59		globalPlugin := filepath.Join(xdg, "ddx", "global", "plugins", pluginName)
60		if err := os.MkdirAll(globalPlugin, 0o755); err != nil {
61			t.Fatalf("mkdir global plugin: %v", err)
62		}
63	
64		gotPath, gotLayer, err := ResolvePlugin(context.Background(), projectRoot, pluginName)
65		if err != nil {
66			t.Fatalf("ResolvePlugin: unexpected error: %v", err)
67		}
68		if gotLayer != "global" {
